"use strict";const spcAjaxURL=window.swcfpcOptions.ajaxUrl,spcAjaxNonce=window.swcfpcOptions.nonce;function swcfpc_lock_screen(){if(!document.querySelector(".swcfpc_please_wait")){const e=document.querySelectorAll("input[type=submit]"),c=document.querySelectorAll("input[type=submit]"),s=document.querySelectorAll("a");e.forEach((e=>{e.classList.add("swcfpc_hide")})),c.forEach((e=>{e.classList.add("swcfpc_hide")})),s.forEach((e=>{e.classList.add("swcfpc_hide")}));const t=document.createElement("div");t.classList.add("swcfpc_please_wait"),document.body.prepend(t)}}function swcfpc_unlock_screen(){const e=document.querySelectorAll("input[type=submit]"),c=document.querySelectorAll("input[type=submit]"),s=document.querySelectorAll("a");e.forEach((e=>{e.classList.remove("swcfpc_hide")})),c.forEach((e=>{e.classList.remove("swcfpc_hide")})),s.forEach((e=>{e.classList.remove("swcfpc_hide")})),document.querySelector(".swcfpc_please_wait")?.remove()}function swcfpc_display_message(e,c){window.alert(`${e}: ${c}`)}async function swcfpc_purge_single_post_cache(e){try{const c=encodeURIComponent(JSON.stringify({post_id:e}));swcfpc_lock_screen();const s=await window.fetch(spcAjaxURL,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=utf-8"},body:`action=swcfpc_purge_single_post_cache&security=${spcAjaxNonce}&data=${c}`,credentials:"same-origin",timeout:1e4});if(s.ok){const e=await s.json();swcfpc_unlock_screen(),"ok"===e.status?swcfpc_display_message("Success",`${e.success_msg}`):swcfpc_display_message("Error",`${e.error}`)}else console.error(`Error: ${s.status} ${s.statusText}`),swcfpc_unlock_screen()}catch(e){window.alert(`Error: ${e.status} ${e.message}`),console.error(e),swcfpc_unlock_screen()}}document.addEventListener("DOMContentLoaded",(()=>{try{document.querySelectorAll(".swcfpc_action_row_single_post_cache_purge").forEach((e=>{e.addEventListener("click",(e=>{e.preventDefault(),swcfpc_purge_single_post_cache(e.currentTarget.dataset.post_id)}))}))}catch(e){console.warn(e)}}));